    ('ENG-L 210', 'STUDIES IN POPULAR LITERATURE AND MASS MEDIA', '34309', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'LH 023', 'Raisa Tolchinsky', 0, NULL, 'Lecture', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'Popular literary modes in England and America, such as detective, western, fantasy; history and theories of "mass" or "popular" culture; uses of literacy. Literary analysis of particular mass media forms, including television drama. Topic varies.', ARRAY['IUB GenEd A&H credit
COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('ENG-L 214', 'LITERARY MASTERPIECES', '37051', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'BH 012', 'Jonathan Elmer', 0, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'L214 covers major Western literary works from the Renaissance to the twenty-first century. Texts are selected from a variety of genres and nations, with an emphasis on works that have been particularly famous and influential. Works by Cervantes, Voltaire, Flaubert, Dostoevsky, Mann, Ibsen, Kafka, and others are typically included. Emphasis will be on making the literature accessible and interesting, relating it to historical events and contexts, and working on important reading and writing skills. Non-English works will be read in English translation.', ARRAY['Transfer Indiana Initiative
IUB GenEd A&H credit
COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('ENG-L 219', 'INTRODUCTION TO ENVIRONMENTAL LITERATURE', '30397', 'Closed', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'BH 209', 'Joshua Pontillo', 0, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Introduces the critical study of environmental writing in anglophone literature, covering texts in multiple genres and modes and examining how literature shapes and intersects with environmental awareness, thinking, and justice. May explore nature writing, science writing, ecopoetry, Cli-Fi, among other genres.', ARRAY['IUB GenEd A&H credit
COLL (CASE) A&H Breadth of Inquiry credit
COLL (CASE) Sustainability Literacy credit'], NULL),
