    ('ENG-L 312', 'LITERARY HISTORY 2: EIGHTEENTH AND NINETEENTH CENTURIES', '30431', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'BH 208', 'Jesse Molesworth', 2, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'A broad overview of the development of British and American literature in the era of empire, industry, and revolution. Tells the story of the expansion of English language and literature.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('ENG-L 318', 'MILTON', '30393', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'LH 004', 'Linda Charnes', 3, NULL, 'Lecture', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'Poetry and prose of John Milton, with special attention to Paradise Lost, Paradise Regained, and Samson Agonistes.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('ENG-L 348', '19TH CENTURY BRITISH FICTION', '13420', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'LH 023', 'Rae Greiner', 0, NULL, 'Lecture', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'Forms, techniques, and theories of fiction as exemplified by such writers as Scott, Dickens, Eliot, and Hardy.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('ENG-L 356', 'AMERICAN POETRY TO 1900', '34145', 'Class Status', 'MW Monday, Wednesday 7:00 PM–9:30 PM', 'BH 229', 'Herbert Marks', 1, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], NULL, ARRAY['COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('ENG-L 357', '20TH CENTURY AMERICAN POETRY', '30436', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'SE 010', 'Nikki Skillman', 0, NULL, 'Lecture', '3', 'SWAIN EAST', ARRAY[]::TEXT[], 'Examination of the general trends and important contributions found in the work of major and minor American poets.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('ENG-L 359', 'AMERICAN LITERATURE, 1960-PRESENT', '30434', 'Closed', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'BH 208', 'Rebekah Sheldon', 0, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Examination of a range of literary forms and developments after the start of the Vietnam War. Special attention may be given to postmodernism, women''s literature, ethnic literature, 1930s protest literature, and radical revisions of genres, forms and narrative strategies in the age of computerization.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('ENG-L 367', 'LITERATURE OF THE BIBLE', '30442', 'Class Status', 'MW Monday, Wednesday 3:55 PM–6:25 PM', 'LH 135', 'Herbert Marks', 4, NULL, 'Lecture', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'Hebrew Bible and New Testament with emphasis on questions of reading and interpretation.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('ENG-L 369', 'STUDIES IN BRITISH AND AMERICAN AUTHORS', '34586', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'BH 012', 'Bob Bledsoe', 0, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Studies in single authors (such as Wordsworth and Melville), groups of authors (such as minority writers), and periods (such as American writers of the 1920s). Topics will vary from semester to semester.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('ENG-L 371', 'CRITICAL PRACTICES', '8859', 'Closed', 'MW Monday, Wednesday 8:00 AM–9:15 AM', 'BH 209', 'Drew Dalton', 0, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Study of and practice in critical methodologies; can be focused on specific topics.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('ENG-L 389', 'FEMINIST LITERARY AND CLUTURAL CRITICISM', '30386', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'LH 004', 'Penelope Anderson', 0, NULL, 'Lecture', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'Selected critical approaches to the issue of gender over time and in various cultural settings. Topics vary including feminist criticism and popular culture, the history of feminist expository prose, deconstructionism and feminism.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('ENG-L 390', 'CHILDREN''S LITERATURE', '34528', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'BH 010', 'Paul Gutjahr', 0, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Survey of a wide range (folk tales, fantasy, realistic fiction, poetry and picture books) of literature for children from the early years to junior high school. Readings from the classics of previous centuries and from the best modern works will be treated from the literary-critical perspective, from which pedagogical conclusions follow. Intended for English majors, for the general students, for teachers past and future, and for parents and librarians.', ARRAY['Transfer Indiana Initiative
COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('ENG-L 391', 'LITERATURE FOR YOUNG ADULTS', '30418', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'LH 004', 'Paul Gutjahr', 5, NULL, 'Lecture', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'Study of books suitable for junior high and high school classroom use. Special stress on works of fiction dealing with contemporary problems, but also including modern classics, biography, science fiction, and other areas of interest to teenage readers.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('ENG-L 395', 'BRITISH AND AMERICAN FILM STUDIES', '37450', 'Class Status', 'MW Monday, Wednesday 5:30 PM–8:00 PM', 'BH 216', 'Walton Muyumba', 8, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Intensive study of specific topics related to film narratives; emphasis on American and/or British film as a cultural phenomenon. Topic varies.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('ENG-L 396', 'AFRICAN AMERICAN LITERATURE', '11380', 'Closed', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'LH 023', 'Walton Muyumba', 0, NULL, 'Lecture', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'Study of a coherent phenomenon of African American literature and culture (such as the Harlem Renaissance, the Black Arts Movement, African American Women''s Autobiographies, Black popular culture and literary expression, recent black fiction or poetry, or a cluster of major authors).', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit
