    ('ENG-L 553', 'STUDIES IN LITERATURE', '32425', 'Closed', NULL, 'OL ONLINE', 'Rebecca Brittenham', 0, NULL, 'Lecture', '4', 'Online Class', ARRAY[]::TEXT[], 'IU Bookstore Strange Case of Dr. Jekyll and Mr. Hyde. 2ndth edition. NA. Price: 5.00 USD Author: Stevenson Publisher: Aziloth Books ISBN: 9781911405764 Course Material Type: Textbook Course Material Status: Required Frankenstein: the 1818 Text. 2018. Price: 11.00 USD Author: Shelley Publisher: Penguin Random House LLC ISBN: 9780143131847 Course Material Type: Textbook Course Material Status: Required Dracula (Norton Critical Edition). 2ndth edition. 2021. Price: 27.75 USD Author: Stoker Publisher: W. W. Norton & Company, Inc. ISBN: 9780393679205 Course Material Type: Textbook Course Material Status: Required', ARRAY[]::TEXT[], NULL),
    ('ENG-L 599', 'INTERNSHIP IN ENGLISH', '3752', 'Class Status', NULL, NULL, 'Jesse Molesworth', 5, NULL, 'Lecture', '1–4', NULL, ARRAY[]::TEXT[], 'Primarily for Special Field Masters of Arts candidates. Requires student''s defining a project and getting both a faculty and external sponsor. Likely external sponsors include IU Foundation, IU Press, advertising agencies, charities, legal or political offices, health agencies, writing centers.', ARRAY[]::TEXT[], NULL),
    ('ENG-L 610', 'READINGS IN LATE MEDIEVAL LITERATURE AND CULTURE', '30373', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'BH 219', 'Patricia Ingham', 1, NULL, 'Readings', '4', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Variable topics in the cultures and literatures of the fourteenth and fifteenth century, may include poetry, drama, prose, performance, and non-literary texts.', ARRAY[]::TEXT[], NULL),
    ('ENG-L 626', 'READINGS IN RESTORATION AND EIGHTEENTH CENTURY LITERATURE AND CULTURE IN ENGLAND, 1660-1790', '30427', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'BH 123', 'Jesse Molesworth', 1, NULL, 'Readings', '4', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Selected readings of texts written in English from the Restoration to the U.S. Constitution. May include all genres and relevant secondary critical or theoretical work, with a possible emphasis on poetry, drama, and/or nonfictional prose, and a focus on reading practices.', ARRAY[]::TEXT[], NULL),
    ('ENG-L 627', 'READINGS IN NINETEENTH-CENTURY BRITISH LITERATURE AND CULTURE, 1790-1900', '35503', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'BH 146', 'Lara Kriegel', 6, NULL, 'Practicum', '4', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Selected readings of nineteenth-century British texts both literary and non-literary. May include all genres and relevant secondary critical or theoretical work, with a possible emphasis on poetry, drama, and/or nonfictional prose, and a focus on reading practices.', ARRAY[]::TEXT[], NULL),
    ('ENG-L 640', 'READINGS IN TRANSATLANTIC LITERATURES', '30390', 'Class Status', 'Tu Tuesday 3:55 PM–6:55 PM', 'BH 317', 'Judith Brown', 6, NULL, 'Readings', '4', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Study of literature from both sides of the Atlantic. Topics might include the impact of travel on cultural identity, justifications for empire and resistance, literary negotiations of national identity, or transatlantic literary and cultural movements.', ARRAY[]::TEXT[], NULL),
    ('ENG-L 646', 'READINGS IN MEDIA, LITERATURE, AND CULTURE', '32714', 'Class Status', NULL, 'OL ONLINE', 'Brian O''Camb', 1, NULL, 'Readings', '4', 'Online Class', ARRAY[]::TEXT[], 'Introductory study of issues in literary editing, textual culture, or digital humanities.', ARRAY[]::TEXT[], NULL),
