    ('ENG-L 744', 'RESEARCH IN DRAMA AND PERFORMANCE', '34499', 'Class Status', 'Th Thursday 5:30 PM–7:45 PM', 'BH 015', 'Teresa Kovacs', 2, NULL, 'Seminar', '4', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Selected topics in the study of dramatic literature, theatre studies, and performance studies.', ARRAY[]::TEXT[], NULL),
    ('ENG-L 769', 'RESEARCH IN LITERATURE AND SCIENCE', '30375', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'BH 219', 'Patricia Ingham', 1, NULL, 'Lecture', '4', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Major developments in modern science, the philosophical issues they raise, and their influence on modern thought and literature.', ARRAY[]::TEXT[], NULL),
    ('ENG-L 790', 'INDEPENDENT STUDY', '1650', 'Class Status', NULL, NULL, 'Jesse Molesworth', 11, NULL, 'Readings', '1–4', NULL, ARRAY[]::TEXT[], 'Seminar level independent study.', ARRAY[]::TEXT[], NULL),
    ('ENG-L 799', 'PH D THESIS', '1651', 'Class Status', NULL, NULL, 'Jesse Molesworth', 62, NULL, 'Independent Study', '1–16', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('ENG-L 799', 'PH D THESIS', '7188', 'Class Status', NULL, NULL, 'Ivan Kreilkamp', 125, NULL, 'Independent Study', '1–16', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('ENG-R 130', 'PUBLIC SPEAKING-HONORS', '8869', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'SB 220', 'Fain Riopelle', 10, NULL, 'Lecture', '3', 'STUDENT BUILDING (FRANCES MORG', ARRAY[]::TEXT[], 'Prepares students in the liberal arts to communicate effectively with public audiences. Emphasizes oral communication as practiced in public contexts: how to advance reasoned claims in public; how to adapt public oral presentations to particular audiences; how to listen to, interpret, and evaluate public discourse; and how to formulate a clear response. For outstanding students, in place of COLL P-155.', ARRAY[]::TEXT[], NULL),
    ('ENG-R 209', 'TOPICS IN RHETORIC AND PUBLIC CULTURE', '13783', 'Closed', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'BH 344', 'Kelsey Alexander', 0, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Examines how rhetorical practice shapes public culture. May focus on a medium or mode of rhetorical practice, such as documentary film, social movement, or political speech; a theme or issue, such as race, gender, or democracy; or a particular historical period. Topic varies.', ARRAY['IUB GenEd A&H credit
COLL (CASE) A&H Breadth of Inquiry credit
COLL INTENSIVE WRITING SECTIONS'], NULL),
    ('ENG-R 209', 'TOPICS IN RHETORIC AND PUBLIC CULTURE', '30376', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'BH 145', 'Kurt Zemlicka', 0, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Examines how rhetorical practice shapes public culture. May focus on a medium or mode of rhetorical practice, such as documentary film, social movement, or political speech; a theme or issue, such as race, gender, or democracy; or a particular historical period. Topic varies.', ARRAY['IUB GenEd A&H credit
COLL (CASE) A&H Breadth of Inquiry credit
COLL INTENSIVE WRITING SECTIONS'], NULL),
    ('ENG-R 210', 'INTRODUCTION TO DIGITAL RHETORIC', '14504', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'LH 025', 'Scot Barnett', 1, NULL, 'Lecture', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'Workshop-oriented course exploring new forms of writing, interaction, and design for rhetorical purposes and digital environments. Emphasis on producing, interpreting, and analyzing traditional and emerging texts and technologies.', ARRAY['COLL INTENSIVE WRITING SECTIONS'], NULL),
    ('ENG-R 214', 'FEMINIST RHETORIC AND PUBLIC ISSUES', '30440', 'Closed', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'WH 109', 'A. Freya Thimsen', 0, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Explores how various kinds of feminist rhetoric address key public issues. Examines how feminist rhetorical strategies are influenced by feminist traditions, seeking to answer: What does "feminism" mean today? Is there even a single meaning? These questions will be addressed in the context of controversial high-profile public issues.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit
COLL INTENSIVE WRITING SECTIONS'], NULL),
    ('ENG-R 224', 'PERSUASION', '30433', 'Closed', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'LH 125', 'Robin Reames', 0, NULL, 'Lecture', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'Motivational appeals in influencing behavior; psychological factors in speaker-audience relationship; contemporary examples of persuasion. Practice in persuasive speaking.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit
COLL INTENSIVE WRITING SECTIONS'], NULL),
    ('ENG-R 224', 'PERSUASION', '34386', 'Closed', 'MW Monday, Wednesday 5:30 PM–6:45 PM', 'BH 105', 'Robert Terrill', 0, NULL, 'Lecture', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'Motivational appeals in influencing behavior; psychological factors in speaker-audience relationship; contemporary examples of persuasion. Practice in persuasive speaking.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit
COLL INTENSIVE WRITING SECTIONS'], NULL),
    ('ENG-R 348', 'ENVIRONMENTAL COMMUNICATION', '14505', 'Closed', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'LH 101', 'Scot Barnett', 0, NULL, 'Lecture', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'This class is grounded in the perspective that symbolic and natural systems are mutually constituted and therefore, the ways we communicate about and with the environment are vital to examine for a sustainable and just future. The focus of the class may vary to engage topics, such as environmental tourism or environmental disasters.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit
COLL INTENSIVE WRITING SECTIONS'], NULL),
    ('ENG-R 355', 'PUBLIC MEMORY IN COMMUNICATION AND CULTURE', '6611', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'BH 209', 'Cynthia Smith', 1, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Examines the contested nature of public memory from a communication and culture perspective. Focuses on the nature of public memory, its methods of perpetuation, its role in shaping citizens, and its implications for society.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('ENG-R 606', 'PEDAGOGY FOR PUBLIC CULTURE', '30435', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'BH 123', 'Katherine Silvester', 2, NULL, 'Readings', '4', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Consideration of fundamental issues in the theories and practices of teaching, with focus on connecting pedagogy and public culture. Teaching understood as a civic art that both participates in public culture and prepares students for civic engagement, particularly as framed by understanding rhetoric as a teaching tradition.', ARRAY[]::TEXT[], NULL),
    ('ENG-R 770', 'RHETORIC IN CONTEMPORARY THEORY', '30439', 'Class Status', 'W Wednesday 11:10 AM–2:10 PM', 'BH 338', 'A. Freya Thimsen', 2, NULL, 'Lecture', '4', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Examines the role of rhetoric in emerging social, political, aesthetic, and cultural theories and on the implications of such theories for rhetorical inquiry.', ARRAY[]::TEXT[], NULL),
