    ('ENG-W 301', 'WRITING FICTION', '3486', 'Class Status', 'TuTh Tuesday, Thursday 8:00 AM–9:15 AM', 'BH 012', 'Samrat Upadhyay', 4, NULL, 'Seminar', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Further exploration in the art of fiction writing.', ARRAY[]::TEXT[], NULL),
    ('ENG-W 301', 'WRITING FICTION', '30377', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'BH 010', 'Angela Jackson-Brown', 0, NULL, 'Seminar', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Further exploration in the art of fiction writing.', ARRAY[]::TEXT[], NULL),
    ('ENG-W 303', 'WRITING POETRY', '4836', 'Class Status', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'BH 010', 'Douglas Case', 1, NULL, 'Seminar', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Further exploration in the art of poetry writing.', ARRAY[]::TEXT[], NULL),
    ('ENG-W 311', 'WRITING CREATIVE NONFICTION', '34323', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'BH 016', 'Brando Skyhorse', 3, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Writing workshop in such modes as personal essay, autobiography, or documentary. Course focuses on understanding and practicing the rhetorical and stylistic choices available to writers of creative nonfiction: options for structure, pacing, language, style, tone, detail, description, authorial presence and voice, etc.', ARRAY[]::TEXT[], NULL),
    ('ENG-W 350', 'ADVANCED EXPOSITORY WRITING', '32577', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'BH 143', 'Robert Betz', 1, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Close examination of the assumptions and choices that govern content and style, and practice in the techniques of producing a variety of researched papers incorporating primary and secondary research, appropriate to audience and purpose.', ARRAY['COLL INTENSIVE WRITING SECTIONS'], NULL),
    ('ENG-W 350', 'ADVANCED EXPOSITORY WRITING', '34384', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'BH 306', 'David Graham', 0, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Close examination of the assumptions and choices that govern content and style, and practice in the techniques of producing a variety of researched papers incorporating primary and secondary research, appropriate to audience and purpose.', ARRAY['COLL INTENSIVE WRITING SECTIONS'], NULL),
    ('ENG-W 381', 'THE CRAFT OF FICTION', '30388', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'LH 125', 'Bob Bledsoe', 5, NULL, 'Lecture', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'Designed primarily for the creative writing student: the study and the practice of the techniques used in the writing of fiction, including point of view, narrative distance, plot, characterization, setting, and tone.', ARRAY[]::TEXT[], NULL),
    ('ENG-W 383', 'THE CRAFT OF POETRY', '13545', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'LH 004', 'Ross Gay', 4, NULL, 'Lecture', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'Designed primarily for the creative writing student: the study and the practice of the techniques used in the writing of poetry, including meter and other rhythmic structures more commonly relied on in nonmetrical or free verse, such as rhyme, alliteration, and stanza structures.', ARRAY[]::TEXT[], NULL),
    ('ENG-W 401', 'ADVANCED FICTION WRITING', '11200', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'BH 012', 'Angela Jackson-Brown', 1, NULL, 'Seminar', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Focused work in the art and profession of fiction writing.', ARRAY[]::TEXT[], NULL),
    ('ENG-W 501', 'PRACTICUM ON THE TEACHING OF COMPOSITION IN COLLEGE', '7019', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'LH 023', 'Katherine Silvester', 12, NULL, 'Lecture', '1–3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'Practical teaching of composition; current theories and policies.', ARRAY[]::TEXT[], NULL),
    ('ENG-W 509', 'INTRODUCTION TO WRITING AND LITERACY STUDIES', '31865', 'Class Status', NULL, 'OL ONLINE', 'Kelly Blewett', 1, NULL, 'Lecture', '4', 'Online Class', ARRAY[]::TEXT[], 'This is the core course in the writing and literacy track of the English master''s program. Students will read, analyze, discuss, and write about key issues in writing and literacy, laying a foundation for further study. Special emphasis will be placed on research methods in this field.', ARRAY[]::TEXT[], NULL),
    ('ENG-W 513', 'WRITING POETRY', '33024', 'Class Status', NULL, 'OL ONLINE', 'Terry Kirts', 2, NULL, 'Lecture', '4', 'Online Class', ARRAY[]::TEXT[], 'Poetry writing workshop on the study of prosody and form (including formal elements of free verse) in the context of writing by class members.', ARRAY[]::TEXT[], NULL),
    ('ENG-W 554', 'PRACTICUM ON THE TEACHING OF CREATIVE WRITING', '1742', 'Class Status', 'F Friday 2:20 PM–5:20 PM', 'BH 106', 'Michael Pontacoloni', 5, NULL, 'Seminar', '2', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Theory and practice of teaching the writing of poetry and fiction, at the college level, with attention to matters of curricular design and classroom technique. Required of those teaching W103 for the first time. Open also to graduate students not in the creative writing program.', ARRAY[]::TEXT[], NULL),
    ('ENG-W 600', 'TOPICS IN RHETORIC AND COMPOSITION', '36790', 'Closed', NULL, 'OL ONLINE', 'Paul Cook', 0, NULL, 'Lecture', '4', 'Online Class', ARRAY[]::TEXT[], 'Covers selected issues in current composition and rhetorical theory.', ARRAY[]::TEXT[], NULL),
    ('ENG-W 602', 'CONTEMPORARY THEORIES IN RHETORIC AND COMPOSITION', '32656', 'Class Status', NULL, 'OL ONLINE', 'Paul Cook', 1, NULL, 'Lecture', '4', 'Online Class', ARRAY[]::TEXT[], 'An introduction to current research in rhetoric and composition. Draws on insights from linguistic theory, cognitive theory and rhetorical theory to develop greater understanding of the writing process and build pedagogical applications.', ARRAY[]::TEXT[], NULL),
    ('ENG-W 611', 'WRITING FICTION 1', '4292', 'Class Status', 'Tu Tuesday 11:10 AM–2:10 PM', 'BH 403', 'Brando Skyhorse', 8, NULL, 'Seminar', '4', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Graduate writing workshop in fiction designed to emphasize storytelling fundamentals while preparing students for a rapidly changing publishing market place.', ARRAY[]::TEXT[], NULL),
    ('ENG-W 613', 'WRITING POETRY 1', '3743', 'Class Status', 'Tu Tuesday 5:30 PM–8:30 PM', 'BH 012', 'Ross Gay', 1, NULL, 'Seminar', '4', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Graduate writing workshop in poetry with a focus on the initial creation and revision of texts. Students will refine the tools of the poetic craft and explore conventions of contemporary poetry.', ARRAY[]::TEXT[], NULL),
    ('ENG-W 680', 'THEORY AND CRAFT OF WRITING', '13543', 'Closed', 'Th Thursday 9:35 AM–12:35 PM', 'BH 106', 'Samrat Upadhyay', 0, NULL, 'Seminar', '4', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Elements of poetic prosody and/or the major fictive techniques: nature of stress, concepts of meter, nature of rhythm, pro sodic uses of syntax, theories of fictive realism, nature of fictive romance, point of view, etc. Students will do some writing. Open also to graduate students not in the creative writing program.', ARRAY[]::TEXT[], NULL),
    ('ENG-W 697', 'INDEPENDENT STUDY IN WRITING 1', '1743', 'Class Status', NULL, NULL, 'Angela Jackson-Brown', 28, NULL, 'Independent Study', '1–4', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('ENG-W 697', 'INDEPENDENT STUDY IN WRITING 1', '6015', 'Class Status', NULL, NULL, 'Angela Jackson-Brown', 30, NULL, 'Independent Study', '1–4', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('ENG-W 697', 'INDEPENDENT STUDY IN WRITING 1', '6908', 'Class Status', NULL, NULL, 'Ivan Kreilkamp', 30, NULL, 'Independent Study', '1–4', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('ENG-W 699', 'M.F.A. THESIS', '1744', 'Class Status', NULL, NULL, 'Angela Jackson-Brown', 14, NULL, 'Independent Study', '1–12', NULL, ARRAY[]::TEXT[], 'Thesis hour credits for MFA students.', ARRAY[]::TEXT[], NULL),
    ('ENG-X 373', 'PROFESSIONAL PRACTICE IN ENGLISH', '7223', 'Class Status', NULL, NULL, 'Judith Brown', 15, NULL, 'Internship', '1–6', NULL, ARRAY[]::TEXT[], 'Supervised, career-related work experience in cooperating institution, agency, or business. Evaluation by employer and Department of English.', ARRAY[]::TEXT[], NULL),
    ('ENG-X 471', 'TEACHING INTERNSHIP IN ENGLISH', '7192', 'Class Status', NULL, NULL, 'Judith Brown', 13, NULL, 'Internship', '1–3', NULL, ARRAY[]::TEXT[], 'Supervised experience in teaching an undergraduate English course. Students are not involved in grading.', ARRAY[]::TEXT[], NULL),
    ('ENG-X 473', 'INTERNSHIP IN ENGLISH', '7216', 'Class Status', NULL, NULL, 'Judith Brown', 8, NULL, 'Internship', '1–3', NULL, ARRAY[]::TEXT[], 'Supervised experience with a departmentally based journal, allied publication, or affiliated organization.', ARRAY[]::TEXT[], NULL),
    ('ENG-X 490', 'INDIVIDUAL READING IN ENGLISH', '7224', 'Class Status', NULL, NULL, 'Judith Brown', 12, NULL, 'Readings', '1–3', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('ENGR-E 101', 'INNOVATION AND DESIGN', '7497', 'Class Status', 'M Monday 1:55 PM–2:45 PM', 'WH 003', 'Mary Loveless', 4, 'Lecture', 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Innovation and Design provides an introduction to Intelligent Systems Engineering. Students learn about engineering and the focus areas through interactive lectures and hands-on activity quests. Students present each quest with a new media to practice presenting data. Students will learn about professional development and start a digital portfolio.', ARRAY['IUB GenEd N&M credit'], NULL),
    ('ENGR-E 101', 'INNOVATION AND DESIGN', '7498', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'IF 4010', 'Mary Loveless', 3, 'Laboratory', 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Innovation and Design provides an introduction to Intelligent Systems Engineering. Students learn about engineering and the focus areas through interactive lectures and hands-on activity quests. Students present each quest with a new media to practice presenting data. Students will learn about professional development and start a digital portfolio.', ARRAY['IUB GenEd N&M credit'], NULL),
