    ('ENGR-E 101', 'INNOVATION AND DESIGN', '9997', 'Closed', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'IF 4010', 'Olgun Sadik', 0, 'Laboratory', 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Innovation and Design provides an introduction to Intelligent Systems Engineering. Students learn about engineering and the focus areas through interactive lectures and hands-on activity quests. Students present each quest with a new media to practice presenting data. Students will learn about professional development and start a digital portfolio.', ARRAY['IUB GenEd N&M credit'], NULL),
    ('ENGR-E 111', 'SOFTWARE SYSTEMS ENGINEERING', '35762', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'AC C002', 'Abhishek Bisht', 2, 'Lecture', 'Lecture', '4', 'CEDAR HALL', ARRAY[]::TEXT[], 'This course covers core aspects of the practice of software engineering, from basic programming concepts to design to development, debugging and maintenance. This course will cover software design, considering abstraction, modularity and encapsulation. It will cover requirements and process management, testing and maintenance, common software structures and software development tools.', ARRAY[]::TEXT[], NULL),
    ('ENGR-E 111', 'SOFTWARE SYSTEMS ENGINEERING', '35767', 'Class Status', 'F Friday 8:45 AM–10:40 AM', 'IF 4012', 'Staff', 18, 'Laboratory', 'Lecture', '4', 'CEDAR HALL', ARRAY[]::TEXT[], 'This course covers core aspects of the practice of software engineering, from basic programming concepts to design to development, debugging and maintenance. This course will cover software design, considering abstraction, modularity and encapsulation. It will cover requirements and process management, testing and maintenance, common software structures and software development tools.', ARRAY[]::TEXT[], NULL),
