    ('ENGR-E 111', 'SOFTWARE SYSTEMS ENGINEERING', '35766', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'I 107', 'Mitja Hmeljak', 5, 'Lecture', 'Lecture', '4', 'CEDAR HALL', ARRAY[]::TEXT[], 'This course covers core aspects of the practice of software engineering, from basic programming concepts to design to development, debugging and maintenance. This course will cover software design, considering abstraction, modularity and encapsulation. It will cover requirements and process management, testing and maintenance, common software structures and software development tools.', ARRAY[]::TEXT[], NULL),
    ('ENGR-E 201', 'COMPUTER SYSTEMS ENGINEERING', '7960', 'Class Status', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'FA 102', 'Jeremy Musser', 6, 'Lecture', 'Lecture', '3', 'FINE ARTS', ARRAY[]::TEXT[], 'This course covers modern computing devices, the computing ecosystem and introductory material in systems programming, computer architecture, operating systems and computer networks. Coursework includes fundamental concepts at the basis of modern computing systems, covering costs in time, space and energy. The curriculum includes basic operational concepts in programming, computer architecture and networking.', ARRAY[]::TEXT[], NULL),
