    ('ENGR-E 221', 'INTELLIGENT SYSTEMS I', '35926', 'Class Status', NULL, 'WB WEB', 'Nasim Anousheh', 1, 'Lecture', NULL, NULL, NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('ENGR-E 221', 'INTELLIGENT SYSTEMS I', '7962', 'Closed', 'MW Monday, Wednesday 10:25 AM–11:15 AM', 'RH 100', 'Nasim Anousheh', 0, 'Lecture', NULL, NULL, NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('ENGR-E 221', 'INTELLIGENT SYSTEMS I', '33686', 'Class Status', 'F Friday 12:45 PM–2:00 PM', 'IF 4063', 'Nasim Anousheh', 26, 'Laboratory', NULL, NULL, NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('ENGR-E 221', 'INTELLIGENT SYSTEMS I', '34818', 'Class Status', 'F Friday 8:00 AM–9:15 AM', 'IF 4063', 'Nasim Anousheh', 6, 'Laboratory', NULL, NULL, NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('ENGR-E 221', 'INTELLIGENT SYSTEMS I', '7963', 'Closed', 'F Friday 9:45 AM–11:00 AM', 'IF 4063', 'Nasim Anousheh', 0, 'Laboratory', NULL, NULL, NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('ENGR-E 250', 'SYSTEMS, SIGNALS, AND CONTROL', '10478', 'Class Status', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'IF 1104', 'Silvina Ferradal', 10, NULL, 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'Many engineering systems are based on signal processing and this course covers fundamental concepts in signals, systems, and control theory. Basic topics are covered, including continuous and discrete time signals and systems, filtering and sampling, Fourier transform and it variants, and basic feedback systems.', ARRAY[]::TEXT[], NULL),
    ('ENGR-E 299', 'ENGINEERING PROFESSIONALIZATION & ETHICS', '8857', 'Class Status', 'W Wednesday 7:05 PM–8:20 PM', 'HH 2057', 'Olgun Sadik', 22, NULL, 'Lecture', '1', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'This course introduces topics in engineering related to professionalism and ethics designed to develop ethical reasoning skills, increase ethical awareness and professionalism, and to analyze ethical dilemmas, specific to engineering. Students will learn ethical principles that can be applied in research, design and development.', ARRAY[]::TEXT[], NULL),
    ('ENGR-E 304', 'INTRODUCTION TO BIOENGINEERING', '10096', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'IF 4012', 'Rachna Mirchandani', 7, NULL, 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'The course introduces the fields of bioengineering and biomedical engineering. Topics include biofabrication, biomanufacturing, bioinstrumentation, drug discovery and delivery, cellular and molecular bioengineering, with a focus on design of different types of instruments and sensors. How to merge the disciplines of engineering and biology for biomedical applications will be discussed.', ARRAY[]::TEXT[], NULL),
    ('ENGR-E 311', 'CIRCUITS AND DIGITAL SYSTEMS', '11541', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'GY 4068', 'Suha Lasassmeh', 18, 'Lecture', 'Lecture', '3', 'GEOLOGICAL SCIENCES', ARRAY[]::TEXT[], 'This course will cover elements of circuits, such as the operation of basic circuit elements, fundamental circuit laws, and analytic techniques in both the time domain and the frequency domain. It will also cover the transistor-level design of circuits in the context of modern integrated-circuit technology.', ARRAY[]::TEXT[], NULL),
    ('ENGR-E 311', 'CIRCUITS AND DIGITAL SYSTEMS', '11542', 'Class Status', 'F Friday 10:20 AM–12:20 PM', 'GY 4068', 'Suha Lasassmeh', 18, 'Laboratory', 'Lecture', '3', 'GEOLOGICAL SCIENCES', ARRAY[]::TEXT[], 'This course will cover elements of circuits, such as the operation of basic circuit elements, fundamental circuit laws, and analytic techniques in both the time domain and the frequency domain. It will also cover the transistor-level design of circuits in the context of modern integrated-circuit technology.', ARRAY[]::TEXT[], NULL),
    ('ENGR-E 313', 'ENGINEERING COMPILERS', '8599', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'I 107', 'Jeremy Siek', 5, NULL, 'Lecture', '3', 'MYLES BRAND HALL', ARRAY[]::TEXT[], 'This course covers the engineering of a compiler, from scanning to parsing, semantic analysis and transformations to code generation and optimization. The emphasis of this course is on the hands-on implementations of various components using industry-standard tools.', ARRAY[]::TEXT[], NULL),
    ('ENGR-E 315', 'DIGITAL DESIGN WITH FPGAS', '11093', 'Closed', 'W Wednesday 3:55 PM–6:55 PM', 'IF 3111', 'Andrew Lukefahr', 0, NULL, 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'This course introduces digital design techniques using field programmable gate arrays (FPGAs). It discusses FPGA architecture, digital design flow using FPGAs, and other technologies associated with field programmable gate arrays. The course study will involve extensive lab projects to give students hands-on experience on designing digital systems on FPGA platforms.', ARRAY[]::TEXT[], NULL),
    ('ENGR-E 318', 'ENGINEERING NETWORKS', '8600', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'IF 1106', 'Jeremy Musser', 0, 'Lecture', 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'This course will cover the engineering of computer networks, considering the architecture and protocols. This course focuses on hands-on implementation and network systems construction.', ARRAY[]::TEXT[], NULL),
    ('ENGR-E 318', 'ENGINEERING NETWORKS', '8601', 'Closed', 'F Friday 1:55 PM–2:45 PM', 'IF 1104', 'Staff', 0, 'Discussion', 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'This course will cover the engineering of computer networks, considering the architecture and protocols. This course focuses on hands-on implementation and network systems construction.', ARRAY[]::TEXT[], NULL),
    ('ENGR-E 340', 'INTRODUCTION TO COMPUTATIONAL BIOENGINEERING', '8742', 'Class Status', 'Tu Tuesday 4:20 PM–6:50 PM', 'IF 0119', 'James Glazier', 16, NULL, 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'This course introduces key computational modeling techniques for bioengineering, with a focus on cell population kinetics, cell signaling, receptor trafficking, pharmacokinetics/pharmacodynamics, and compartmental and systems physiology methods. Concepts in control theory and optimization will also be applied to steer the modeled biological systems towards design objectives.', ARRAY[]::TEXT[], NULL),
    ('ENGR-E 345', 'WEARABLE SENSORS', '10805', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'IF 4063', 'Gregory Lewis', 12, NULL, 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'The purpose of this course is to give you hands-on experience with wearable sensors and a foundation to understand their design and operation. The course will also serve as a partial survey of sensor designs in human physiological and behavioral monitoring.', ARRAY[]::TEXT[], NULL),
    ('ENGR-E 390', 'UNDERGRADUATE INDEPENDENT STUDY', '7873', 'Class Status', NULL, NULL, 'Paul Macklin, Tiana Iruoje', 16, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], 'Independent research based on existing literature or original work. A report, in the style of a departmental technical report, is required.', ARRAY[]::TEXT[], NULL),
    ('ENGR-E 390', 'UNDERGRADUATE INDEPENDENT STUDY', '13139', 'Class Status', NULL, NULL, 'Weihua Guan', 20, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], 'Independent research based on existing literature or original work. A report, in the style of a departmental technical report, is required.', ARRAY[]::TEXT[], NULL),
    ('ENGR-E 390', 'UNDERGRADUATE INDEPENDENT STUDY', '15297', 'Class Status', NULL, NULL, 'Weihua Guan', 1, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], 'Independent research based on existing literature or original work. A report, in the style of a departmental technical report, is required.', ARRAY[]::TEXT[], NULL),
    ('ENGR-E 399', 'TOPICS IN INTELLIGENT SYSTEMS ENGINEERING', '8939', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'HD TBA', 'Alexander Gumennik', 8, NULL, 'Lecture', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Variable topic. Emphasis is on new developments and research in Intelligent Systems Engineering.', ARRAY[]::TEXT[], NULL),
