    ('ENGR-E 399', 'TOPICS IN INTELLIGENT SYSTEMS ENGINEERING', '34539', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'IF 4012', 'Hui Min Leung', 22, NULL, 'Lecture', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Variable topic. Emphasis is on new developments and research in Intelligent Systems Engineering.', ARRAY[]::TEXT[], NULL),
    ('ENGR-E 399', 'TOPICS IN INTELLIGENT SYSTEMS ENGINEERING', '34561', 'Class Status', 'TuTh Tuesday, Thursday 8:00 AM–9:15 AM', 'IF 4010', 'Bryce Himebaugh', 18, NULL, 'Lecture', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Variable topic. Emphasis is on new developments and research in Intelligent Systems Engineering.', ARRAY[]::TEXT[], NULL),
    ('ENGR-E 399', 'TOPICS IN INTELLIGENT SYSTEMS ENGINEERING', '35577', 'Class Status', 'Th Thursday 10:00 AM–1:00 PM', 'IF 4111', 'Andrew Lukefahr', 24, NULL, 'Lecture', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Variable topic. Emphasis is on new developments and research in Intelligent Systems Engineering.', ARRAY[]::TEXT[], NULL),
    ('ENGR-E 399', 'TOPICS IN INTELLIGENT SYSTEMS ENGINEERING', '37073', 'Class Status', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'LI 026', 'Byung-Cheol Min', 5, NULL, 'Lecture', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Variable topic. Emphasis is on new developments and research in Intelligent Systems Engineering.', ARRAY[]::TEXT[], NULL),
    ('ENGR-E 399', 'TOPICS IN INTELLIGENT SYSTEMS ENGINEERING', '35578', 'Class Status', 'Tu Tuesday 7:05 PM–8:20 PM', 'WB WEB', 'Winona Snapp-Childs, Shawn Slavin', 13, NULL, 'Lecture', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Variable topic. Emphasis is on new developments and research in Intelligent Systems Engineering.', ARRAY[]::TEXT[], NULL),
    ('ENGR-E 399', 'TOPICS IN INTELLIGENT SYSTEMS ENGINEERING', '11556', 'Closed', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'IF 4012', 'Fan Chen', 0, NULL, 'Lecture', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Variable topic. Emphasis is on new developments and research in Intelligent Systems Engineering.', ARRAY[]::TEXT[], NULL),
    ('ENGR-E 416', 'ENGINEERING CLOUD COMPUTING', '10561', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'GA 1112', 'Prateek Sharma', 28, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'The course covers basic concepts on programming models and tools of cloud computing to support data intensive science applications. Students will get to know the latest research topics of cloud platforms, parallel algorithms, storage and high level language for proficiency with a complex ecosystem of tools that span many disciplines.', ARRAY[]::TEXT[], NULL),
    ('ENGR-E 451', 'SIMULATING NANOSCALE SYSTEMS', '33682', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'WY 015', 'Vikram Jadhao', 20, NULL, 'Lecture', '3', 'WYLIE HALL', ARRAY[]::TEXT[], 'Students will learn how to model and simulate material behavior at the nanoscale. Analysis and control of shape, assembly, and flow behavior in soft nanomaterials will be discussed. Applications to engineering problems at the nanoscale will be emphasized. Optimization methods, nonequilibrium systems, and parallel computing will be covered.', ARRAY[]::TEXT[], NULL),
    ('ENGR-E 471', 'MICROFLUIDIC DEVICES AND SYSTEMS', '13577', 'Class Status', 'W Wednesday 3:10 PM–5:40 PM', 'AC C114', 'Feng Guo', 10, NULL, 'Lecture', '3', 'CEDAR HALL', ARRAY[]::TEXT[], 'This course gives a fundamental introduction to the science and technology of miniaturization and its applications in creating microfluidic and nanofluidic devices. It discusses methods, tools and measuring devices to design and create micro-/nano-systems, and biomedical applications of these devices and systems such as pressure sensors, mixing devices.', ARRAY[]::TEXT[], NULL),
    ('ENGR-E 483', 'INFORMATION VISUALIZATION', '33684', 'Class Status', NULL, 'WB WEB', 'Andreas Bueckle', 27, 'Lecture', 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course provides students with a working knowledge on how to visualize abstract information and hands-on experience in the application of this knowledge to specific domains, different tasks, and diverse, possibly non-technical users.', ARRAY[]::TEXT[], NULL),
    ('ENGR-E 483', 'INFORMATION VISUALIZATION', '33685', 'Class Status', 'Th Thursday 5:30 PM–6:45 PM', 'FA 102', 'Andreas Bueckle', 27, 'Discussion', 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course provides students with a working knowledge on how to visualize abstract information and hands-on experience in the application of this knowledge to specific domains, different tasks, and diverse, possibly non-technical users.', ARRAY[]::TEXT[], NULL),
    ('ENGR-E 484', 'SCIENTIFIC VISUALIZATION', '9282', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'HD TBA', 'Eric Wernert', 37, NULL, 'Lecture', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'This course teaches basic principles of human cognition and perception; techniques and algorithms for designing and critiquing scientific visualizations in different domains (neuro, nano, bio-medicine, IoT, smart cities); hands-on experience using modern tools for designing scientific visualizations that provide novel and/or actionable insights; 3D printing and augmented reality deployment; teamwork/project management expertise.', ARRAY[]::TEXT[], NULL),
    ('ENGR-E 490', 'ENGINEERING CAPSTONE DESIGN I', '8810', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'GY 4068', 'Suha Lasassmeh', 11, NULL, 'Lecture', '3', 'GEOLOGICAL SCIENCES', ARRAY[]::TEXT[], 'Engineering Capstone Design I is one of two capstone requirements for all Intelligent Systems Engineering students. Students will design engineering projects based on their areas of concentration, which will be supported by dedicated faculty members. Students may choose to conduct advanced research, develop prototypes, design new products or redesign existing products.', ARRAY[]::TEXT[], NULL),
    ('ENGR-E 500', 'INTRODUCTION TO THE INTELLIGENT SYSTEMS ENGINEERING PROGRAM', '8371', 'Class Status', 'M Monday 3:10 PM–4:00 PM', 'BH 006', 'Jonathan Ponniah', 17, NULL, 'Lecture', '1', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'This course provides an introduction to Intelligent Systems Engineering and an overview of the various degree specializations that are available. ISE is a set of modern Systems Engineering areas with various interrelations. This course provides a broad introduction and details of faculty research areas.', ARRAY[]::TEXT[], NULL),
    ('ENGR-E 501', 'INTRODUCTION TO COMPUTER ENGINEERING', '11095', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'IF 4063', 'Lei Jiang', 8, NULL, 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'This course covers computer engineering and parallel computer architecture for HPC in intelligent systems engineering. Topics include multi-core processors, cache coherence, data centric computing, SIMD, GPU, FPGA, accelerators, and heterogeneous computing architecture. The course will focus on fundamental parallel computer architectures, evaluation and the tradeoffs in design, and their use.', ARRAY[]::TEXT[], NULL),
    ('ENGR-E 503', 'INTRODUCTION TO INTELLIGENT SYSTEMS', '8372', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'I E130', 'Jonathan Ponniah', 24, NULL, 'Lecture', '3', 'MYLES BRAND HALL', ARRAY[]::TEXT[], 'Systems Engineering (SE) can refer to several different concepts, disciplines, and technical skills needed in designing and building systems of systems. This course covers fundamental principle and five use cases with special attention to challenges and opportunities coming from modern computing infrastructure, the internet of things and artificial intelligence.', ARRAY[]::TEXT[], NULL),
    ('ENGR-E 504', 'INTRODUCTION TO BIOENGINEERING', '8373', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'IF 4012', 'Rachna Mirchandani', 7, NULL, 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'The course introduces the fields of bioengineering and biomedical engineering. Topics include biofabrication, biomanufacturing, bioinstrumentation, drug discovery and delivery, cellular and molecular bioengineering, with a focus on design of different types of instruments and sensors. How to merge the disciplines of engineering and biology for biomedical applications will be discussed.', ARRAY[]::TEXT[], NULL),
    ('ENGR-E 506', 'INTRODUCTION TO NEURO-ENGINEERING GRADUATE PROGRAM IN INTELLIGENT SYSTEMS ENGINEERING', '8374', 'Class Status', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'PV A203', 'Eleftherios Garyfallidis', 5, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'Understand concepts of neuro-engineering with an applied mathematics focus. Learn the principles of building intelligent machines for neuro-engineering. This is an introductory course to ISE Masters and Ph.D. program in Neuro-Engineering. It will have guest lectures, and the basic material will be interleaved with talks on relevant Bloomington campus research.', ARRAY[]::TEXT[], NULL),
    ('ENGR-E 513', 'ENGINEERING COMPILERS', '9077', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'I 107', 'Jeremy Siek', 4, NULL, 'Lecture', '3', 'MYLES BRAND HALL', ARRAY[]::TEXT[], 'This course covers the engineering of a compiler, from scanning to parsing, semantic analysis and transformations to code generation and optimization. The emphasis of this course is on the hands-on implementations of various components using industry-standard tools.', ARRAY[]::TEXT[], NULL),
    ('ENGR-E 516', 'ENGINEERING CLOUD COMPUTING', '10098', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'GA 1112', 'Prateek Sharma', 28, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'This course covers basic concepts on programming models and tools of cloud computing to support data intensive science applications. Students will get to know the latest research topics of cloud platforms, parallel algorithms, storage and high level language for proficiency with a complex ecosystem of tools that span many disciplines.', ARRAY[]::TEXT[], NULL),
    ('ENGR-E 516', 'ENGINEERING CLOUD COMPUTING', '14588', 'Class Status', 'M Monday 4:20 PM–6:50 PM', 'WY 005', 'Fengguang Song', 40, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'This course covers basic concepts on programming models and tools of cloud computing to support data intensive science applications. Students will get to know the latest research topics of cloud platforms, parallel algorithms, storage and high level language for proficiency with a complex ecosystem of tools that span many disciplines.', ARRAY[]::TEXT[], NULL),
    ('ENGR-E 516', 'ENGINEERING CLOUD COMPUTING', '14587', 'Class Status', NULL, 'OL ONLINE', 'Fengguang Song', 15, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'This course covers basic concepts on programming models and tools of cloud computing to support data intensive science applications. Students will get to know the latest research topics of cloud platforms, parallel algorithms, storage and high level language for proficiency with a complex ecosystem of tools that span many disciplines.', ARRAY[]::TEXT[], NULL),
    ('ENGR-E 518', 'ENGINEERING NETWORKS', '8885', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'IF 1106', 'Jeremy Musser', 0, 'Lecture', 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'This course will cover the engineering of computer networks, considering the architecture and protocols. This course focuses on hands-on implementation and network systems construction.', ARRAY[]::TEXT[], NULL),
    ('ENGR-E 518', 'ENGINEERING NETWORKS', '8886', 'Closed', 'F Friday 3:10 PM–4:00 PM', 'IF 1104', 'Staff', 0, 'Discussion', 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'This course will cover the engineering of computer networks, considering the architecture and protocols. This course focuses on hands-on implementation and network systems construction.', ARRAY[]::TEXT[], NULL),
    ('ENGR-E 518', 'ENGINEERING NETWORKS', '10798', 'Closed', 'F Friday 4:20 PM–5:10 PM', 'IF 1104', 'Staff', 0, 'Discussion', 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'This course will cover the engineering of computer networks, considering the architecture and protocols. This course focuses on hands-on implementation and network systems construction.', ARRAY[]::TEXT[], NULL),
    ('ENGR-E 533', 'DEEP LEARNING SYSTEMS', '9095', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'I E150', 'Jonathan Ponniah', 43, NULL, 'Lecture', '3', 'MYLES BRAND HALL', ARRAY[]::TEXT[], 'This course teaches the pipeline for building state-of-the-art deep learning-based intelligent systems. It covers general training mechanisms and acceleration options that use GPU computing libraries and parallelization techniques running on high performance computing systems. The course also aims at deploying the networks to the low-powered hardware systems.', ARRAY[]::TEXT[], NULL),
    ('ENGR-E 533', 'DEEP LEARNING SYSTEMS', '9096', 'Class Status', NULL, 'WB WEB', 'Jonathan Ponniah', 25, NULL, 'Lecture', '3', 'MYLES BRAND HALL', ARRAY[]::TEXT[], 'This course teaches the pipeline for building state-of-the-art deep learning-based intelligent systems. It covers general training mechanisms and acceleration options that use GPU computing libraries and parallelization techniques running on high performance computing systems. The course also aims at deploying the networks to the low-powered hardware systems.', ARRAY[]::TEXT[], NULL),
    ('ENGR-E 534', 'BIG DATA APPLICATIONS', '11552', 'Class Status', NULL, 'WB WEB', 'Nasim Anousheh', 28, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This is an overview course of Big Data Applications covering a broad range of problems and solutions. It covers cloud computing technologies and includes a project. Algorithms are introduced and illustrated.', ARRAY[]::TEXT[], NULL),
    ('ENGR-E 537', 'RAPID PROTOTYPING FOR ENGINEERS', '8498', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'HD TBA', 'Alexander Gumennik', 8, NULL, 'Lecture', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Protoyping - materialization of concepts - is essential for design and engineering of a product. The course overviews the modern computer aided design (CAD) - computer aided manufacturing (CAM) approach to prototyping. Students will perform a case study practicum, characterizing performance envelope of fused deposition modeling (FDM) 3D printer.', ARRAY[]::TEXT[], NULL),
    ('ENGR-E 542', 'INTRODUCTION TO COMPUTATIONAL BIOENGINEERING', '10090', 'Class Status', 'Tu Tuesday 4:20 PM–6:50 PM', 'IF 0119', 'James Glazier', 16, NULL, 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'This course introduces key computational modeling techniques for bioengineering, with a focus on cell population kinetics, cell signaling, receptor trafficking, pharmacokinetics/pharmacodynamics, and compartmental and systems physiology methods. Concepts in control theory and optimization will also be applied to steer the modeled biological systems towards design objectives.', ARRAY[]::TEXT[], NULL),
    ('ENGR-E 545', 'WEARABLE SENSORS', '10807', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'IF 4063', 'Gregory Lewis', 12, NULL, 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'The purpose of this course is to give you hands-on experience with wearable sensors and a foundation to understand their design and operation. The course will also serve as a partial survey of sensor designs in human physiological and behavioral monitoring.', ARRAY[]::TEXT[], NULL),
    ('ENGR-E 551', 'SIMULATING NANOSCALE SYSTEMS', '33683', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'WY 015', 'Vikram Jadhao', 6, NULL, 'Lecture', '3', 'WYLIE HALL', ARRAY[]::TEXT[], 'Students will learn how to model and simulate material behavior at the nanoscale. Analysis and control of shape, assembly, and flow behavior in soft nanomaterials will be discussed. Applications to engineering problems at the nanoscale will be emphasized. Optimization methods, nonequilibrium systems, and parallel computing will be covered.', ARRAY[]::TEXT[], NULL),
    ('ENGR-E 571', 'MICROFLUIDIC DEVICES AND SYSTEMS', '15228', 'Class Status', 'W Wednesday 3:10 PM–5:40 PM', 'AC C114', 'Feng Guo', 5, NULL, 'Lecture', '3', 'CEDAR HALL', ARRAY[]::TEXT[], 'This course gives a fundamental introduction to the science and technology of miniaturization and its applications in creating microfluidic and nanofluidic devices. It discusses methods, tools and measuring devices to design and create micro-/nano-systems, and biomedical applications of these devices and systems such as pressure sensors, mixing devices.', ARRAY[]::TEXT[], NULL),
    ('ENGR-E 583', 'INFORMATION VISUALIZATION', '34305', 'Class Status', NULL, 'WB WEB', 'Andreas Bueckle', 27, 'Lecture', 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course provides students with a working knowledge on how to visualize abstract information and hands-on experience in the application of this knowledge to specific domains, different tasks, and diverse, possibly non-technical users.', ARRAY[]::TEXT[], NULL),
    ('ENGR-E 583', 'INFORMATION VISUALIZATION', '34306', 'Class Status', 'Th Thursday 5:30 PM–6:45 PM', 'FA 102', 'Andreas Bueckle', 27, 'Discussion', 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course provides students with a working knowledge on how to visualize abstract information and hands-on experience in the application of this knowledge to specific domains, different tasks, and diverse, possibly non-technical users.', ARRAY[]::TEXT[], NULL),
    ('ENGR-E 584', 'SCIENTIFIC VISUALIZATION', '9283', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'HD TBA', 'Eric Wernert', 37, NULL, 'Lecture', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Teaches basic principles of human cognition and perception; techniques and algorithms for designing and critiquing scientific visualizations in different domains (neuro, nano, bio-medicine, IoT, smart cities); hands-on experience using modern tools for designing scientific visualizations that provide novel and/or actionable insights; 3D printing and augmented reality deployment; teamwork/project management expertise.', ARRAY[]::TEXT[], NULL),
    ('ENGR-E 591', 'GRADUATE INTERNSHIP', '9093', 'Class Status', NULL, NULL, 'Weihua Guan', 25, NULL, 'Internship', '1–6', NULL, ARRAY[]::TEXT[], 'Students gain professional work experience in an industry or research organization setting, using skills and knowledge acquired in Intelligent Systems course work.', ARRAY[]::TEXT[], NULL),
