    ('ENGR-E 788', 'MASTER''S THESIS', '8920', 'Class Status', NULL, NULL, 'Weihua Guan', 19, NULL, 'Internship', '1–6', NULL, ARRAY[]::TEXT[], 'Readings and research under the supervision of the master''s thesis advisor, leading to a thesis at a level admissible as a departmental technical report.', ARRAY[]::TEXT[], NULL),
    ('ENGR-E 890', 'THESIS READINGS AND RESEARCH', '8919', 'Class Status', NULL, NULL, 'Weihua Guan', 30, NULL, 'Research', '1–12', NULL, ARRAY[]::TEXT[], 'Research under the direction of a member of the graduate faculty leading to a Ph.D. dissertation.', ARRAY[]::TEXT[], NULL),
    ('ENGR-G 901', 'ADVANCED RESEARCH', '8921', 'Class Status', NULL, NULL, 'Weihua Guan', 16, NULL, 'Research', '6', NULL, ARRAY[]::TEXT[], 'Available to graduate students who have completed all course requirements for their doctorates, have passed doctoral qualifying examinations, and have the requisite number of degree credit hours, this course provides the advanced research student with a forum for sharing ideas and problems under the supervision of a senior researcher.', ARRAY[]::TEXT[], NULL),
    ('ENGR-G 901', 'ADVANCED RESEARCH', '9848', 'Class Status', NULL, NULL, 'Weihua Guan', 20, NULL, 'Research', '6', NULL, ARRAY[]::TEXT[], 'Available to graduate students who have completed all course requirements for their doctorates, have passed doctoral qualifying examinations, and have the requisite number of degree credit hours, this course provides the advanced research student with a forum for sharing ideas and problems under the supervision of a senior researcher.', ARRAY[]::TEXT[], NULL),
    ('ENGR-Y 395', 'CAREER DEVELOPMENT FOR ISE MAJORS', '11031', 'Class Status', 'Tu Tuesday 11:10 AM–12:25 PM', 'SB 150', 'David Gregoire', 1, NULL, 'Lecture', '1', 'STUDENT BUILDING (FRANCES MORG', ARRAY[]::TEXT[], 'Develop skills and knowledge that enable you to successfully pursue your career search, both at the time of graduation and later as you progress through your career. The course covers techniques and strategies which make your job search more efficient and effective.', ARRAY[]::TEXT[], NULL),
    ('EURO-E 100', 'BEGINNING MODERN GREEK I', '3059', 'Class Status', 'MTuWTh Monday, Tuesday, Wednesday, Thursday 12:45 PM–1:35 PM', 'GA 0003', 'Frank Hess', 9, NULL, 'Lecture', '4', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], NULL, ARRAY['IUB GenEd World Language class'], NULL),
    ('EURO-E 100', 'BEGINNING MODERN GREEK I', '8415', 'Class Status', 'MW Monday, Wednesday 5:30 PM–6:20 PM', 'GA 0005', 'Frank Hess', 13, NULL, 'Lecture', '4', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], NULL, ARRAY['IUB GenEd World Language class'], NULL),
    ('EURO-E 200', 'INTERMEDIATE MODERN GREEK I', '3060', 'Class Status', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'SY 0013', 'Frank Hess', 11, NULL, 'Lecture', '3', 'SYCAMORE HALL', ARRAY[]::TEXT[], NULL, ARRAY['IUB GenEd World Language class'], NULL),
    ('EURO-E 300', 'ADVANCED MODERN GREEK I: CULTURAL LITERACY AND CURRENT EVENTS', '5947', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'GA 0007', 'Frank Hess', 8, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Assists advanced students in developing both their communicative competency in modern Greek and their awareness of Greek culture and society. The emphasis on popular culture begun in E250 continues and is augmented by an emphasis on current events.', ARRAY[]::TEXT[], NULL),
    ('EURO-E 491', 'ELEM MODERN GRK FOR GRAD STDS', '3061', 'Class Status', 'MTuWTh Monday, Tuesday, Wednesday, Thursday 12:45 PM–1:35 PM', 'GA 0003', 'Frank Hess', 9, NULL, 'Discussion', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('EURO-G 100', 'BEGINNING IRISH I', '32769', 'Class Status', 'MW Monday, Wednesday 10:25 AM–12:05 PM', 'WB WEB', 'Dylan Cooper', 19, NULL, 'Lecture', '4', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'An introductory course to modern Irish (Gaeilge). Focus on beginner-level development of major language skills: simple speaking and listening proficiency, basic reading, and simple writing composition. Proficiency will be developed through the foundations of Irish grammar and vocabulary. Irish culture will be discussed as critical to Irish language revitalization.', ARRAY[]::TEXT[], NULL),
    ('EURO-G 100', 'BEGINNING IRISH I', '37273', 'Class Status', 'MW Monday, Wednesday 10:25 AM–12:05 PM', 'WB WEB', 'Dylan Cooper', 19, NULL, 'Lecture', '4', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'An introductory course to modern Irish (Gaeilge). Focus on beginner-level development of major language skills: simple speaking and listening proficiency, basic reading, and simple writing composition. Proficiency will be developed through the foundations of Irish grammar and vocabulary. Irish culture will be discussed as critical to Irish language revitalization.', ARRAY[]::TEXT[], NULL),
    ('EURO-G 200', 'INTERMEDIATE IRISH I', '34908', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'WB WEB', 'Dylan Cooper', 2, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Focuses on development of major intermediate level language skills: speaking and understanding more complex ideas, reading more advanced texts, and gaining proficiency in higher-level writing composition. Proficiency will be developed through expanded use of grammar and vocabulary. Irish culture will be discussed as a critical element accompanying language revitalization.', ARRAY[]::TEXT[], NULL),
    ('EURO-G 200', 'INTERMEDIATE IRISH I', '37274', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'WB WEB', 'Dylan Cooper', 2, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Focuses on development of major intermediate level language skills: speaking and understanding more complex ideas, reading more advanced texts, and gaining proficiency in higher-level writing composition. Proficiency will be developed through expanded use of grammar and vocabulary. Irish culture will be discussed as a critical element accompanying language revitalization.', ARRAY[]::TEXT[], NULL),
    ('EURO-W 200', 'INTRODUCTION TO EUROPEAN STUDIES', '14099', 'Closed', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'GA 0001', 'Colton Ames', 0, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'This course provides an introductory survey to the study of Europe from a multi-disciplinary perspective. Students will examine selected topics from Europe''s historical and contemporary development, giving them a broad overview of the field of European Studies and the ways that it may connect with other fields of study.', ARRAY['IUB GenEd S&H credit
