    ('FOLK-E 251', 'ETHNOMUSICOLOGY AND THE SOCIAL SCIENCES', '11331', 'Class Status', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'C2 203', 'Julianne Graper', 4, NULL, 'Lecture', '3', 'CLASSROOM-OFFICE BUILDING', ARRAY[]::TEXT[], 'Provides basic theoretical approaches to the study of ethnomusicology, emphasizing its relationship to other social science disciplines such as anthropology, sociology, economics, and political science. May be repeated with a different topic for a maximum of 6 credit hours.', ARRAY['IUB GenEd S&H credit
COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('FOLK-E 290', 'MUSIC AND VIOLENCE', '32121', 'Closed', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'JH 001', 'David McDonald', 0, NULL, 'Lecture', '3', 'BIOLOGY BUILDING', ARRAY[]::TEXT[], 'Exploration of the dynamics of music and violence, focusing on the role of music in generating and sustaining societal conflict. Consideration of the various ways in which music has been a tool for transforming conflict and ameliorating trauma.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('FOLK-E 295', 'SURVEY OF HIP HOP', '4284', 'Closed', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'WB WEB', 'Fernando Orejuela', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Examines rap music and hip hop culture as artistic and socio-cultural phenomena with emphasis on historical, cultural, economic, and political contexts. Topics include the coexistence of various hip hop styles, their appropriation by the music industry, and controversies resulting from the exploitation of hip hop as a commodity for national and global consumption.', ARRAY['IUB GenEd A&H credit
COLL (CASE) A&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Diversity in U.S.'], NULL),
    ('FOLK-E 522', 'THE STUDY OF ETHNOMUSICOLOGY', '4248', 'Class Status', 'W Wednesday 12:00 PM–2:30 PM', 'C2 272', 'Eduardo Herrera', 2, NULL, 'Seminar', '3', 'CLASSROOM-OFFICE BUILDING', ARRAY[]::TEXT[], 'Introduction to discipline: history, scope, definitions of ethnomusicology; key issues, points of debate; ethnomusicologists and their work; resources for research, teaching, and other activities in which ethnomusicologists engage. Background for more specialized courses in fieldwork, theory, intellectual history, and world areas.', ARRAY[]::TEXT[], NULL),
    ('FOLK-E 533', 'APPLIED ETHNOMUSICOLOGY', '32124', 'Class Status', 'Tu Tuesday 1:30 PM–4:00 PM', 'C2 272', 'Rebecca Dirksen', 3, NULL, 'Seminar', '3', 'CLASSROOM-OFFICE BUILDING', ARRAY[]::TEXT[], 'Investigates histories and trajectories of applied ethnomusicology, while preparing students to conceptualize and develop their own work in the sub-field. Will map definitions of applied, advocacy, activist, engaged, and public sector work and trace connections to other disciplines. Discussions focus on research approaches, tools, and methodologies within applied ethnomusicology circles.', ARRAY[]::TEXT[], NULL),
