    ('FOLK-F 225', 'FORMS OF COMMEMORATION', '30222', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'WY 101', 'Robert Dobler', 0, NULL, 'Lecture', '3', 'WYLIE HALL', ARRAY[]::TEXT[], 'Examines forms of commemoration in order to define their essential features and to describe how they operate in society. Highlights what we might call folk commemoration, those informal modes of remembrance that are part of community tradition.', ARRAY['IUB GenEd A&H credit
COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('FOLK-F 252', 'FOLKLORE AND THE HUMANITIES (V.T.)', '12333', 'Closed', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'C2 203', 'Dorian Juric', 0, NULL, 'Lecture', '3', 'CLASSROOM-OFFICE BUILDING', ARRAY[]::TEXT[], 'Basic theoretical approaches to the study of folklore, emphasizing the relationship to other humanistic disciplines such as literary and religious studies and history.', ARRAY['IUB GenEd A&H credit
COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('FOLK-F 253', 'FOLKLORE AND THE SOCIAL SCIENCES', '13804', 'Closed', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'BH 003', 'Robert Dobler', 0, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Basic theoretical approaches to the study of folklore, emphasizing the relationship to other social science disciplines such as semiotics and anthropology.', ARRAY['IUB GenEd S&H credit
COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('FOLK-F 330', 'FOLK CULTURE AND RELATED FIELDS', '14071', 'Closed', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'C2 203', 'Barbara Hillers', 0, NULL, 'Lecture', '3', 'CLASSROOM-OFFICE BUILDING', ARRAY[]::TEXT[], 'Studies of folk culture in relationship to other fields. Focuses on such interdisciplinary topics as folk culture in relationship to language, literature, psychology, history, religion, sociology, musicology, or anthropology.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('FOLK-F 330', 'FOLK CULTURE AND RELATED FIELDS', '32069', 'Closed', 'M Monday 11:10 AM–1:40 PM', 'C2 272', 'Max Jack', 0, NULL, 'Lecture', '3', 'CLASSROOM-OFFICE BUILDING', ARRAY[]::TEXT[], 'Studies of folk culture in relationship to other fields. Focuses on such interdisciplinary topics as folk culture in relationship to language, literature, psychology, history, religion, sociology, musicology, or anthropology.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('FOLK-F 359', 'EXPLORING JEWISH IDENTITY TODAY', '32257', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'BH 144', 'Jeremiah Lockwood', 4, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'When people describe what they believe, do, create, or experience as "Jewish," what do they mean? Using multiple perspectives and multiple forms of media, we will explore how different communities--from orthodox Jews to evangelical Christians--incorporate senses of Judaism into their cultural, religious, racial ethnic, and artistic identities.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Diversity in U.S.'], NULL),
    ('FOLK-F 363', 'WOMEN''S FOLKLORE/FOLKLIFE/FOLK MUSIC', '13809', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'C2 203', 'Solimar Otero', 1, NULL, 'Lecture', '3', 'CLASSROOM-OFFICE BUILDING', ARRAY[]::TEXT[], 'Focuses on women''s folk traditions in terms of life cycle and role and explores the range of women''s occupations and related traditional knowledge. Looks at women as traditional verbal, visual, or musical artists.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('FOLK-F 364', 'CHILDREN''S FOLKLORE/FOLKLIFE/FOLK MUSIC', '5885', 'Closed', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'C2 102', 'Fernando Orejuela', 0, NULL, 'Lecture', '3', 'CLASSROOM-OFFICE BUILDING', ARRAY[]::TEXT[], 'The traditional rhymes, stories, games, folklife, or music associated with "the culture of childhood." The role these forms play in peer-group activity and in the social and cognitive development of the child.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Diversity in U.S.'], NULL),
    ('FOLK-F 367', 'FOLKLORE OF THE SOUTH', '13808', 'Closed', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'C2 203', 'Brandon Barker', 0, NULL, 'Lecture', '3', 'CLASSROOM-OFFICE BUILDING', ARRAY[]::TEXT[], 'Surveys folkloric traditions practiced in the southern states, including folk speech, festival celebrations, foodways, folk music, and folk religion. Considered together, the folklore from disparate geographic and cultural spaces of the broadly defined South present a complex picture of Dixie that forces us to question our Southern assumptions.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Diversity in U.S.'], NULL),
    ('FOLK-F 399', 'READINGS FOR HONORS', '6007', 'Class Status', NULL, NULL, 'Fernando Orejuela', 1, NULL, 'Independent Study', '3', NULL, ARRAY[]::TEXT[], 'Independent but guided readings in preparation for the honors thesis in Folklore and Ethnmusicology.', ARRAY[]::TEXT[], NULL),
    ('FOLK-F 401', 'METHODS AND THEORIES', '5161', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'C2 102', 'Fernando Orejuela', 7, NULL, 'Seminar', '3', 'CLASSROOM-OFFICE BUILDING', ARRAY[]::TEXT[], 'Introduces students to the main methods and theories in the two fields composing folklore and ethnomusicology. Explores both the common ground linking these fields and some key areas of difference, delving into basic aspects of method and theory as practiced by folklorists and ethnomusicologists.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('FOLK-F 404', 'TOPICS IN FOLKLORE', '12334', 'Closed', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'SW 217', 'Barbara Hillers', 0, NULL, 'Lecture', '3', 'SWAIN WEST', ARRAY[]::TEXT[], 'Explores in depth a particular topics in the study of folklore, folklife, or music. Courses of unusual, integrative, or experimental nature.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('FOLK-F 406', 'MUSEUM PRACTICE IN FOLKLORE STUDIES', '32235', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'C2 102', 'Jason Jackson', 1, NULL, 'Seminar', '3', 'CLASSROOM-OFFICE BUILDING', ARRAY[]::TEXT[], 'An introduction to curatorial practice in museums, with an emphasis on museums of ethnography and cultural history. With campus collections serving as laboratories for course activities, students will work with objects of material culture and engage in a range of activities central to professional practice in museums and other collections.', ARRAY[]::TEXT[], NULL),
    ('FOLK-F 430', 'FOLKLORE AND RELATED DISCIPLINES', '32236', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'FX 150', 'Jon Kay', 0, NULL, 'Lecture', '3', 'MCCALLA', ARRAY[]::TEXT[], 'Advanced studies of folklore and/or ethnomusicology in relationship to other disciplines. Focuses on such interdisciplinary topics as folklore and literature, folklore and psychology; folklore and history; folklore and religion; or folklore, culture and society.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('FOLK-F 516', 'FOLKLORE THEORY IN PRACTICE', '1768', 'Class Status', 'Th Thursday 9:15 AM–11:45 AM', 'C2 272', 'Jason Jackson', 3, NULL, 'Seminar', '3', 'CLASSROOM-OFFICE BUILDING', ARRAY[]::TEXT[], 'An introduction to scholarly practice, developing an integrated idea of folklore as a topic of study as a way to conduct research.', ARRAY[]::TEXT[], NULL),
    ('FOLK-F 713', 'FOOD: ART AND IDENTITY', '32128', 'Closed', 'M Monday 2:30 PM–5:00 PM', 'C2 272', 'Pravina Shukla', 0, NULL, 'Lecture', '3', 'CLASSROOM-OFFICE BUILDING', ARRAY[]::TEXT[], 'This seminar centers on the topic of food -- the production, preparation, and consumption -- applying a material culture model to the study of food. While food is an expression of cultural identities, it is also a powerful vehicle for the expression of individual identities, preferences, and aesthetics.', ARRAY[]::TEXT[], NULL),
    ('FOLK-F 722', 'COLLOQUIUM IN THEORETICAL FOLKLORE/ETHNOMUSICOLOGY', '32126', 'Class Status', 'Tu Tuesday 10:00 AM–12:30 PM', 'C2 272', 'Eduardo Herrera', 6, NULL, 'Lecture', '3', 'CLASSROOM-OFFICE BUILDING', ARRAY[]::TEXT[], 'Intensive examination of social scientific theories and an assessment of their relevance to folklore/ethnomusicology scholarship.', ARRAY[]::TEXT[], NULL),
    ('FOLK-F 755', 'FOLKLORE, CULTURE AND SOCIETY', '32237', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'FX 150', 'Jon Kay', 1, NULL, 'Lecture', '3', 'MCCALLA', ARRAY[]::TEXT[], 'Relationship of folklore, culture, and social organization. Beliefs, values and social relations in the folklore of various societies. Special topics include gender, children, and ethnicity.', ARRAY[]::TEXT[], NULL),
    ('FOLK-F 800', 'RESEARCH IN FOLKLORE & ETHNOMUSICOLOGY', '8270', 'Class Status', NULL, NULL, 'Pravina Shukla', 1, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], 'Individual research/readings course with faculty member.', ARRAY[]::TEXT[], NULL),
    ('FOLK-F 800', 'RESEARCH IN FOLKLORE & ETHNOMUSICOLOGY', '1769', 'Closed', NULL, NULL, 'Pravina Shukla', 0, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], 'Individual research/readings course with faculty member.', ARRAY[]::TEXT[], NULL),
    ('FOLK-F 802', 'TRADITIONAL ARTS INDIANA', '4260', 'Class Status', NULL, NULL, 'Jon Kay', 1, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], 'Designed as a practicum for students to work collaboratively in applying the methods and approaches of folklore studies to public needs and public programs. Students will engage in a variety of outreach projects linking the university to the larger community in the areas of public arts and culture and cultural documentation.', ARRAY[]::TEXT[], NULL),
    ('FOLK-F 803', 'PRACTICUM IN FOLKLORE/ETHNOMUSICOLOGY', '1770', 'Class Status', NULL, NULL, 'Pravina Shukla', 10, NULL, 'Practicum', '1–3', NULL, ARRAY[]::TEXT[], 'Individualized, supervised work in publicly oriented programs in folklore or ethnomusicology, such as public arts agencies, museums, historical commissions, and archives. Relevant readings and written report required.', ARRAY[]::TEXT[], NULL),
    ('FOLK-F 804', 'SPECIAL TOPICS IN FOLKLORE/ETHNOMUSICOLOGY', '12335', 'Class Status', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'SW 217', 'Barbara Hillers', 3, NULL, 'Lecture', '1–3', 'SWAIN WEST', ARRAY[]::TEXT[], 'Topics will be selected in areas of folklore or ethnomusicology not covered in depth in existing courses.', ARRAY[]::TEXT[], NULL),
    ('FOLK-F 804', 'SPECIAL TOPICS IN FOLKLORE/ETHNOMUSICOLOGY', '13814', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'C2 203', 'Solimar Otero', 0, NULL, 'Lecture', '1–3', 'SWAIN WEST', ARRAY[]::TEXT[], 'Topics will be selected in areas of folklore or ethnomusicology not covered in depth in existing courses.', ARRAY[]::TEXT[], NULL),
    ('FOLK-F 806', 'MUSEUM PRACTICUM IN FOLKLORE STUDIES', '7917', 'Class Status', NULL, NULL, 'Pravina Shukla', 2, NULL, 'Practicum', '1–3', NULL, ARRAY[]::TEXT[], 'Folklore studies-oriented practicum at a campus or community-based museum or systematic research collection. Participatory activities will be supplemented by reading and writing activities. May be repeated for up to 6 credit hours.', ARRAY[]::TEXT[], NULL),
    ('FOLK-F 850', 'THESIS/PROJECT/DISSERTATION', '1771', 'Class Status', NULL, NULL, 'Pravina Shukla', 14, NULL, 'Independent Study', '1–12', NULL, ARRAY[]::TEXT[], 'Thesis/Project credit for M.A. students writing a thesis or completing a master''s project and Ph.D. candidates.', ARRAY[]::TEXT[], NULL),
    ('FOLK-F 850', 'THESIS/PROJECT/DISSERTATION', '4258', 'Class Status', NULL, NULL, 'Pravina Shukla', 14, NULL, 'Independent Study', '1–12', NULL, ARRAY[]::TEXT[], 'Thesis/Project credit for M.A. students writing a thesis or completing a master''s project and Ph.D. candidates.', ARRAY[]::TEXT[], NULL),
    ('FOLK-G 901', 'ADVANCED RESEARCH', '1772', 'Class Status', NULL, NULL, 'Pravina Shukla', 15, NULL, 'Research', '6', NULL, ARRAY[]::TEXT[], 'Available to graduate students who have completed all course requirements for their doctorates, have passed doctoral qualifying examinations, and have the requisite number of degree credit hours, this course provides the advanced research student with a forum for sharing ideas and problems under the supervision of a senior researcher.', ARRAY[]::TEXT[], NULL),
    ('FOLK-X 402', 'TRADITIONAL ARTS INDIANA', '4259', 'Class Status', NULL, NULL, 'Jon Kay', 1, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], 'Designed as a practicum for students to work collaboratively in applying the methods and approaches of folklore studies to public needs and public programs. Students will engage in a variety of outreach projects linking the university to the larger community in the areas of public arts and culture and cultural documentation.', ARRAY[]::TEXT[], NULL),
    ('FOLK-X 476', 'MUSEUM PRACTICUM IN FOLKLORE', '7170', 'Class Status', NULL, NULL, 'Pravina Shukla', 5, NULL, 'Practicum', '1–3', NULL, ARRAY[]::TEXT[], 'Independent, supervised, folklore-oriented practicum at a campus or community museum or systematic research collection relevant to folklore, ethnography, or cultural history. Participatory activities will be supplemented by reading and writing activities.', ARRAY[]::TEXT[], NULL),
    ('FOLK-X 477', 'FIELD EXPERIENCE IN FOLKLORE/ETHNOMUSICOLOGY', '7231', 'Class Status', NULL, NULL, 'Pravina Shukla', 1, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], 'Field experience and study involving individualized, supervised work in publicly oriented programs in folklore or ethnomusicology, such as public arts agencies, museums, historical commissions, and archives. Relevant readings and written reports required.', ARRAY[]::TEXT[], NULL),
    ('FOLK-X 490', 'INDIVIDUAL STUDY IN FOLKLORE', '7200', 'Class Status', NULL, NULL, 'Pravina Shukla', 3, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], 'May include fieldwork or library research components.', ARRAY[]::TEXT[], NULL),
    ('FREN-F 606', 'CAPSTONE PROJECT IN FRENCH TEACHING', '34328', 'Closed', NULL, 'OL ONLINE', 'Scooter Pegram', 0, NULL, 'Independent Study', '3', 'Online Class', ARRAY[]::TEXT[], 'Designed to be taken during the final semester of the MAT program to complete the student''s academic training and further their professional development. Students work with a faculty advisor on an extended research essay or a classroom project consisting of a pedagogical portfolio relevant to their work as teachers.', ARRAY[]::TEXT[], NULL),
    ('FREN-F 667', 'SEMINAR IN FRANCOPHONE STUDIES', '31770', 'Class Status', NULL, 'OL ONLINE', 'Scooter Pegram', 4, NULL, 'Lecture', '3', 'Online Class', ARRAY[]::TEXT[], 'This course will examine the major currents in Francophone literature and culture of Africa, Asia, Oceania, and the Caribbean with emphasis on the colonial and post colonial periods.', ARRAY[]::TEXT[], NULL),
