    ('FRIT-F 252', 'INTERMEDIATE FRENCH CONVERSATION II', '30381', 'Class Status', NULL, NULL, 'Nicolas Valazza', 3, NULL, 'Practice', '1', NULL, ARRAY[]::TEXT[], 'This companion course to F250 gives beginning students the opportunity to practice conversational French in a relaxed setting with peers. Led by advanced students of French working under faculty guidance, group activities may include discussion, games, magazine/newspaper/movie discussions, cultural events, cooking, etc. S/F grading. No credit for French major.', ARRAY[]::TEXT[], NULL),
    ('FRIT-F 300', 'FRENCH AND FRANCOPHONE STUDIES: INTRODUCTION', '4585', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'BH 315', 'Nicolas Noe', 2, NULL, 'Seminar', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'This course introduces students to different levels of style and expression and to written argumentation in French. Literary texts, films, and other media representing various periods and genres provide the basis for in-class discussion and for exercises designed to develop oral and written fluency. Topics vary by section. Conducted in French.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('FRIT-F 300', 'FRENCH AND FRANCOPHONE STUDIES: INTRODUCTION', '8842', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'BH 016', 'Guillaume Ansart', 3, NULL, 'Seminar', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'This course introduces students to different levels of style and expression and to written argumentation in French. Literary texts, films, and other media representing various periods and genres provide the basis for in-class discussion and for exercises designed to develop oral and written fluency. Topics vary by section. Conducted in French.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('FRIT-F 300', 'FRENCH AND FRANCOPHONE STUDIES: INTRODUCTION', '1806', 'Closed', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'PY 111', 'Jordan Howard', 0, NULL, 'Seminar', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'This course introduces students to different levels of style and expression and to written argumentation in French. Literary texts, films, and other media representing various periods and genres provide the basis for in-class discussion and for exercises designed to develop oral and written fluency. Topics vary by section. Conducted in French.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('FRIT-F 300', 'FRENCH AND FRANCOPHONE STUDIES: INTRODUCTION', '14698', 'Closed', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'BH 016', 'Guillaume Ansart', 0, NULL, 'Seminar', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'This course introduces students to different levels of style and expression and to written argumentation in French. Literary texts, films, and other media representing various periods and genres provide the basis for in-class discussion and for exercises designed to develop oral and written fluency. Topics vary by section. Conducted in French.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('FRIT-F 305', 'STAGE AND PAGE', '13618', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'FQ B002', 'Eric MacPhail', 5, NULL, 'Lecture', '3', 'MARTIN HALL', ARRAY[]::TEXT[], 'Theatre and literature of ideas by authors from the classical tradition to the 21st century. Readings and discussion in French.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('FRIT-F 313', 'ADVANCED GRAMMAR', '30395', 'Closed', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'ED 1250', 'Geoffrey Tacinelli', 0, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Intensive study of French grammar including in-depth review and exploration of advanced topics such as the passive, the causative, and indirect discourse.', ARRAY[]::TEXT[], NULL),
    ('FRIT-F 314', 'CREATIVE AND CRITICAL WRITING IN FRENCH', '34307', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'ED 2280', 'Julie Malet', 2, NULL, 'Practice', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Designed to improve command of written French and build vocabulary through intensive writing. Practice with a variety of literary, expository, and communicative writing styles. Preparation or reinforcement for 300-level classes and study abroad.', ARRAY[]::TEXT[], NULL),
    ('FRIT-F 364', 'LA FRANCE ACTUELLE', '30308', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'GY 1042', 'Brett Bowles', 0, NULL, 'Lecture', '3', 'GEOLOGICAL SCIENCES', ARRAY[]::TEXT[], 'Interdisciplinary introduction to 21st-century French culture, society, politics in an international perspective. Special emphasis on comparison to the US and the Francophone world. Key topics include the structure of French government; France and the European Union and OIF; policies regarding race, ethnicity, religion, and civil rights; policing and socioeconomic ghettoization.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Global Civ & Culture'], NULL),
    ('FRIT-F 375', 'THEMES ET PERSPECTIVES LITTERAIRES ET CULTURELS', '13620', 'Class Status', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'WH 116', 'Vincent Bouchard', 1, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Study of a specific subject or theme (e. g., society and the individual, courtly love and its influence on French culture, West African francophone cinema, or satire in literature and theater). All work in French.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Global Civ & Culture'], NULL),
